import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline
import math

# Define the fused CUDA kernel for conv + scale + channel_min
fused_conv_scale_min_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <vector>
#include <algorithm>

template<typename scalar_t>
__global__ void fused_conv_scale_min_kernel(
    const scalar_t* input,
    const scalar_t* weight,
    const scalar_t* bias,
    scalar_t* output,
    const float scale_factor,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int height,
    const int width,
    const int kernel_size,
    const int pad,
    const int stride
) {
    const int output_h = (height + 2 * pad - kernel_size) / stride + 1;
    const int output_w = (width + 2 * pad - kernel_size) / stride + 1;

    // Each thread handles one spatial position for one batch
    const int spatial_idx = blockIdx.x * blockDim.x + threadIdx.x;
    const int spatial_size = output_h * output_w;
    const int total_spatial = batch_size * spatial_size;

    if (spatial_idx >= total_spatial) return;

    const int b = spatial_idx / spatial_size;
    const int spatial_pos = spatial_idx % spatial_size;
    const int h_out = spatial_pos / output_w;
    const int w_out = spatial_pos % output_w;

    scalar_t channel_min = scalar_t(1e30);

    // For each output channel
    for (int oc = 0; oc < out_channels; ++oc) {
        scalar_t value = bias ? bias[oc] : scalar_t(0);

        // Convolution operation
        for (int ic = 0; ic < in_channels; ++ic) {
            for (int kh = 0; kh < kernel_size; ++kh) {
                for (int kw = 0; kw < kernel_size; ++kw) {
                    int h_in = h_out * stride - pad + kh;
                    int w_in = w_out * stride - pad + kw;

                    if (h_in >= 0 && h_in < height && w_in >= 0 && w_in < width) {
                        int input_idx = ((b * in_channels + ic) * height + h_in) * width + w_in;
                        int weight_idx = ((oc * in_channels + ic) * kernel_size + kh) * kernel_size + kw;

                        value += input[input_idx] * weight[weight_idx];
                    }
                }
            }
        }

        // Apply scaling
        value = value * scalar_t(scale_factor);

        // Track minimum across channels
        if (value < channel_min) {
            channel_min = value;
        }
    }

    // Store the minimum value for this spatial position
    output[spatial_idx] = channel_min;
}

torch::Tensor fused_conv_scale_min_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float scale_factor,
    int stride,
    int padding
) {
    auto batch_size = input.size(0);
    auto in_channels = input.size(1);
    auto height = input.size(2);
    auto width = input.size(3);
    auto out_channels = weight.size(0);
    auto kernel_size = weight.size(2);

    int output_h = (height + 2 * padding - kernel_size) / stride + 1;
    int output_w = (width + 2 * padding - kernel_size) / stride + 1;

    auto output = torch::zeros({batch_size, 1, output_h, output_w}, 
                              torch::TensorOptions().dtype(input.dtype()).device(input.device()));

    int total_spatial = batch_size * output_h * output_w;
    const int block_size = 256;
    const int num_blocks = (total_spatial + block_size - 1) / block_size;

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "fused_conv_scale_min_cuda", ([&] {
        fused_conv_scale_min_kernel<scalar_t><<<num_blocks, block_size>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
            output.data_ptr<scalar_t>(),
            scale_factor,
            batch_size,
            in_channels,
            out_channels,
            height,
            width,
            kernel_size,
            padding,
            stride
        );
    }));

    cudaDeviceSynchronize();
    return output;
}
"""

fused_conv_scale_min_cpp_source = """
